// portal-a05-detalle — validar_firma_ts_rol.
// Lee el raw body desde BINARIO ('data'); recomputa HMAC-SHA256 sobre los bytes
// EXACTOS (D-C-29). Revalida ts (300s), rol (allowlist del wrapper, D-C-39),
// action binding (D-C-41) y -NUEVO en A05- el payload id_reserva (D-C-40, 2da defensa:
// el smoke directo pega aca sin gateway). Whitelist: solo el numero.
const crypto = require('crypto');

// Secreto: SOLO desde Variables de n8n ($vars.VITA_HMAC_SECRET). En Modo B (n8n Cloud SIN
// Variables) se PEGA el secreto real reemplazando el placeholder. El template commiteado queda
// sanitizado; el secreto vive solo en el nodo de la instancia.
const SECRET = (typeof $vars !== 'undefined' && $vars && $vars.VITA_HMAC_SECRET)
  ? $vars.VITA_HMAC_SECRET
  : '__PEGAR_SECRETO_O_USAR_VARIABLE__';

// Assert duro POR PREFIJO (L-C-10): sobrevive al find-replace del placeholder completo.
if (!SECRET || SECRET.startsWith('__PEGAR_')) {
  throw new Error('VITA_HMAC_SECRET no configurado en n8n Variables; abortando (assert duro).');
}

const item = $input.first();
const wh = item.json;

// 1) Raw body como Buffer EXACTO. Prioridad: binario 'data'. Fallback: wh.rawBody (L-C-05).
let buf = null;
try {
  if (item.binary && item.binary.data) {
    buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  }
} catch (e) {
  buf = null;
}
if (!buf) {
  const rawField = wh.rawBody;
  if (Buffer.isBuffer(rawField)) buf = rawField;
  else if (rawField && rawField.type === 'Buffer' && Array.isArray(rawField.data)) buf = Buffer.from(rawField.data);
  else if (typeof rawField === 'string') buf = Buffer.from(rawField, 'utf8');
}
if (!buf) {
  return [{ json: { ok_firma: false, motivo: 'raw_body_ausente', ambiente_esperado: null, rol: null, action: null, ts: null, id_reserva: null } }];
}

// 2) Firma recibida en el header.
const headers = wh.headers || {};
const sigHeader = headers['x-vita-signature'] || headers['X-Vita-Signature'] || '';

// 3) HMAC recomputado sobre los MISMOS bytes.
const expected = 'sha256=' + crypto.createHmac('sha256', SECRET).update(buf).digest('hex');

// 4) Comparacion timing-safe (requiere igual longitud).
let firmaOk = false;
try {
  const a = Buffer.from(sigHeader);
  const b = Buffer.from(expected);
  firmaOk = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  firmaOk = false;
}
if (!firmaOk) {
  return [{ json: { ok_firma: false, motivo: 'firma_invalida', ambiente_esperado: null, rol: null, action: null, ts: null, id_reserva: null } }];
}

// 5) Parseo (firma ya validada sobre bytes crudos).
let body;
try {
  body = JSON.parse(buf.toString('utf8'));
} catch (e) {
  return [{ json: { ok_firma: false, motivo: 'payload_invalido', ambiente_esperado: null, rol: null, action: null, ts: null, id_reserva: null } }];
}

// 6) Ventana de ts (anti-replay liviano, D-C-29): |now - ts| <= 300s.
const ts = Number(body.ts);
if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > 300000) {
  return [{ json: { ok_firma: false, motivo: 'ts_fuera_de_ventana', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts: body.ts ?? null, id_reserva: null } }];
}

// 7) Allowlist de rol del wrapper (D-C-39, 2da defensa). A05 = vicky/socio (sin jenny, D-C-03).
const ROLES_OK = ['vicky', 'socio'];
if (!ROLES_OK.includes(body.rol)) {
  return [{ json: { ok_firma: false, motivo: 'rol_no_permitido', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts, id_reserva: null } }];
}

// 8) Action binding (D-C-41): EXPECTED_ACTION = reserva.detalle (A05).
const EXPECTED_ACTION = 'reserva.detalle';
if (body.action !== EXPECTED_ACTION) {
  return [{ json: { ok_firma: false, motivo: 'accion_desconocida', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts, id_reserva: null } }];
}

// 9) Payload (A05, D-C-40): id_reserva entero positivo seguro. isSafeInteger rechaza decimales,
// NaN/Infinity y enteros fuera del rango seguro de JS. typeof number rechaza strings.
const idRaw = (body.payload && typeof body.payload === 'object' && !Array.isArray(body.payload))
  ? body.payload.id_reserva : undefined;
if (typeof idRaw !== 'number' || !Number.isSafeInteger(idRaw) || idRaw <= 0) {
  return [{ json: { ok_firma: false, motivo: 'payload_invalido', ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts, id_reserva: null } }];
}

return [{ json: { ok_firma: true, motivo: null, ambiente_esperado: body.ambiente_esperado ?? null, rol: body.rol ?? null, action: body.action ?? null, ts, id_reserva: idRaw } }];

// portal-a05-detalle — verificar_acceso. Compara ambiente y arma el envelope de rechazo
// (D-C-18/35). En exito marca {ok:true} para habilitar el IF; el envelope final de exito lo
// arma el render.
const v = $('validar_firma_ts_rol').first().json;
const ambItem = $('leer_ambiente').first();
const real = (ambItem && ambItem.json) ? (ambItem.json.valor ?? null) : null;

function envErr(code, message, detail) {
  return [{ json: { ok: false, error: { code, message, detail: detail ?? null } } }];
}

if (!v.ok_firma) {
  const msgs = {
    firma_invalida: 'firma HMAC invalida o ausente',
    ts_fuera_de_ventana: 'timestamp fuera de la ventana permitida (300s)',
    payload_invalido: 'payload invalido (id_reserva ausente o no entero positivo)',
    raw_body_ausente: 'no llego el raw body (activa Raw Body en el Webhook)',
    rol_no_permitido: 'rol no habilitado para esta accion',
    accion_desconocida: 'accion no corresponde a este endpoint'
  };
  return envErr(v.motivo, msgs[v.motivo] || 'rechazado', null);
}

if (v.ambiente_esperado !== real) {
  return envErr('ambiente_incorrecto', 'el sobre no corresponde a este entorno', { esperado: v.ambiente_esperado, real });
}

return [{ json: { ok: true } }];

// ===== portal-a05-detalle — nodo Code (render JSON) =====
// Detalle de UNA reserva por id_reserva. Contrato D-C-43: data:{reserva,pagos}, montos
// NUMERICOS crudos (el frontend formatea es-AR; debe renderizar como TEXTO, no innerHTML).
// Read-only. Privacidad (D-C-03): SOLO montos de ESTA reserva + sus pagos. saldo_real se
// recalcula en SQL (LATERAL) con pagos confirmados (sena/saldo, monto_recibido) -reafirma
// D-C-40, no se confia en reservas.monto_saldo-. NADA de reparto/cascada/mayor/societario.
// PII huesped: nombre/telefono/email; SIN dni ni notas internas del huesped. Las notas de la
// reserva (notas, notas_reserva) van separadas dentro de 'reserva'.

function safeAll(nodeName, keyField) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    const rows = items.map(it => it.json).filter(j => j && j[keyField] !== undefined && j[keyField] !== null);
    return { ok: true, rows };
  } catch (e) { return { ok: false, rows: [] }; }
}

// NUMERIC de Postgres llega como string; el calculo (saldo_real) ya se hizo en SQL, aca solo
// transportamos el numero (D-C-43). num() devuelve null si no es finito.
function num(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

const resR = safeAll('PG: leer reserva', 'id_reserva');
const pagR = safeAll('PG: leer pagos', 'id_pago');

// Cualquier read fallido => error_interno limpio (sin filtrar SQL/n8n crudo, D-C-18). Una
// reserva sin pagos NO es error: pagR.ok=true con rows=[].
if (!resR.ok || !pagR.ok) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar el detalle', detail: null } } }];
}

// Cero filas en la reserva = id inexistente => no_encontrado (permitido en el gateway).
if (resR.rows.length === 0) {
  return [{ json: { ok: false, error: { code: 'no_encontrado', message: 'reserva inexistente', detail: null } } }];
}

const r = resR.rows[0];

const reserva = {
  id_reserva: r.id_reserva,
  id_cabana: r.id_cabana,
  cabana: r.cabana,
  fecha_checkin: r.fecha_checkin,
  fecha_checkout: r.fecha_checkout,
  hora_checkin: r.hora_checkin,
  hora_checkout: r.hora_checkout,
  personas: r.personas,
  estado: r.estado_reserva,
  canal_origen: r.canal_origen,
  monto_total: num(r.monto_total),
  monto_sena: num(r.monto_sena),
  monto_saldo_registrado: num(r.monto_saldo_registrado),
  total_pagado_confirmado: num(r.total_pagado_confirmado),
  saldo_real: num(r.saldo_real),
  encargado_semana: r.encargado_semana ?? null,
  mascotas: r.mascotas === true,
  detalle_mascotas: r.detalle_mascotas ?? null,
  ninos: r.ninos ?? null,
  notas: r.notas ?? null,
  notas_reserva: r.notas_reserva ?? null,
  created_at: r.created_at,
  huesped: {
    id_huesped: r.id_huesped,
    nombre: r.huesped_nombre ?? null,
    telefono: r.huesped_telefono ?? null,
    email: r.huesped_email ?? null
  }
};

const pagos = pagR.rows.map(p => ({
  id_pago: p.id_pago,
  tipo: p.tipo,
  medio_pago: p.medio_pago,
  monto_esperado: num(p.monto_esperado),
  monto_recibido: num(p.monto_recibido),
  moneda: p.moneda,
  estado: p.estado,
  es_automatico: p.es_automatico === true,
  validado_en: p.validado_en ?? null,
  created_at: p.created_at
}));

return [{ json: { ok: true, data: { reserva, pagos } } }];
